import{_ as a,o,c as t,ai as i}from"./chunks/framework.DyvBZb4W.js";const p=JSON.parse('{"title":"FAQ","description":"","frontmatter":{},"headers":[],"relativePath":"en/mods/sts2-map-enhance/faq.md","filePath":"en/mods/sts2-map-enhance/faq.md","lastUpdated":1779646093000}'),r={name:"en/mods/sts2-map-enhance/faq.md"};function n(s,e,d,l,h,c){return o(),t("div",null,[...e[0]||(e[0]=[i('<h1 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h1><h2 id="what-does-map-enhance-mod-do" tabindex="-1">What does Map Enhance Mod do? <a class="header-anchor" href="#what-does-map-enhance-mod-do" aria-label="Permalink to &quot;What does Map Enhance Mod do?&quot;">​</a></h2><p>It improves Slay the Spire 2 map readability with room-type tinting, route analysis, in-game color controls, opacity controls, brightness controls, and live previews.</p><h2 id="does-it-change-gameplay" tabindex="-1">Does it change gameplay? <a class="header-anchor" href="#does-it-change-gameplay" aria-label="Permalink to &quot;Does it change gameplay?&quot;">​</a></h2><p>No. It changes how map information is presented. It does not add rewards, change route generation, or automatically pick routes.</p><h2 id="is-route-analysis-an-optimal-route-solver" tabindex="-1">Is route analysis an optimal-route solver? <a class="header-anchor" href="#is-route-analysis-an-optimal-route-solver" aria-label="Permalink to &quot;Is route analysis an optimal-route solver?&quot;">​</a></h2><p>No. It is a lightweight planning aid with heuristic scoring based on HP, gold, shops, elites, and rest-site buffers.</p><h2 id="why-are-boss-or-ancient-nodes-not-tinted" tabindex="-1">Why are Boss or Ancient nodes not tinted? <a class="header-anchor" href="#why-are-boss-or-ancient-nodes-not-tinted" aria-label="Permalink to &quot;Why are Boss or Ancient nodes not tinted?&quot;">​</a></h2><p>They currently keep vanilla behavior to avoid conflicts with the game&#39;s hover, animation, and special-node behavior.</p><h2 id="where-can-i-change-colors" tabindex="-1">Where can I change colors? <a class="header-anchor" href="#where-can-i-change-colors" aria-label="Permalink to &quot;Where can I change colors?&quot;">​</a></h2><p>Open:</p><p><code>Settings -&gt; 地图配置 / Map Config</code></p><p>You can edit each room type&#39;s color, opacity, and brightness there.</p><h2 id="is-there-a-quick-toggle" tabindex="-1">Is there a quick toggle? <a class="header-anchor" href="#is-there-a-quick-toggle" aria-label="Permalink to &quot;Is there a quick toggle?&quot;">​</a></h2><p>Yes. Press <code>F8</code> while the map is open to toggle map tinting.</p><h2 id="why-is-the-config-file-named-json-txt" tabindex="-1">Why is the config file named <code>.json.txt</code>? <a class="header-anchor" href="#why-is-the-config-file-named-json-txt" aria-label="Permalink to &quot;Why is the config file named `.json.txt`?&quot;">​</a></h2><p>The game may treat every <code>*.json</code> file in the mod folder as a mod manifest. The map color config uses <code>map_color_config.json.txt</code> to avoid being misread.</p><h2 id="which-files-are-required" tabindex="-1">Which files are required? <a class="header-anchor" href="#which-files-are-required" aria-label="Permalink to &quot;Which files are required?&quot;">​</a></h2><p>At minimum, the mod needs <code>sts2_map_mod.dll</code> and <code>sts2_map_mod.pck</code>. The folder should also keep <code>sts2_map_mod.json</code> and <code>map_color_config.json.txt</code>.</p><h2 id="can-this-mod-be-used-commercially" tabindex="-1">Can this mod be used commercially? <a class="header-anchor" href="#can-this-mod-be-used-commercially" aria-label="Permalink to &quot;Can this mod be used commercially?&quot;">​</a></h2><p>No. It is released for non-commercial use only unless prior written permission is granted.</p><h2 id="can-this-mod-be-reuploaded-or-mirrored" tabindex="-1">Can this mod be reuploaded or mirrored? <a class="header-anchor" href="#can-this-mod-be-reuploaded-or-mirrored" aria-label="Permalink to &quot;Can this mod be reuploaded or mirrored?&quot;">​</a></h2><p>No. Do not reupload this mod to other websites, mirrors, download portals, cloud-drive collections, paid modpacks, or any third-party distribution channel without written permission. Do not distribute modified builds without permission. Please download the files only from the official website, Nexus Mods, or download links explicitly provided by the author.</p>',23)])])}const u=a(r,[["render",n]]);export{p as __pageData,u as default};
